const toStr = (v) => String(v ?? '').trim();
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const getEnv = (key) => {
  try {
    if ($env && $env[key]) return String($env[key]).trim();
  } catch (_e) {}
  try {
    const p = (typeof globalThis !== 'undefined' && globalThis.process && globalThis.process.env)
      ? globalThis.process.env[key]
      : '';
    if (p) return String(p).trim();
  } catch (_e) {}
  return '';
};

const raw = $json || {};
const message = toStr(raw.chatInput || raw.message || raw.text || raw.input || '');
if (!message) throw new Error('[Normalize Chat Input] mensagem vazia.');

const lower = norm(message);
const sessionId = toStr(raw.sessionId || raw.session_id || raw.chatSessionId || raw.metadata?.sessionId || 'default');

const getStore = () => {
  if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  if (this && typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  throw new Error('[Normalize Chat Input] static data indisponivel no Code node.');
};

const store = getStore();
if (!store.chatMemory) store.chatMemory = {};
if (!store.chatModes) store.chatModes = {};
if (!store.impactDrafts) store.impactDrafts = {};
if (!store.impactPrecheck) store.impactPrecheck = {};
if (!store.awaitingImpactNeed) store.awaitingImpactNeed = {};
if (!store.pendingImpactProceed) store.pendingImpactProceed = {};
if (!store.lastSuggestedImpactPayload) store.lastSuggestedImpactPayload = {};
if (!store.qaCache) store.qaCache = {};
if (!store.precheckCache) store.precheckCache = {};
if (!Array.isArray(store.chatMemory[sessionId])) store.chatMemory[sessionId] = [];

if (!('chatModeGlobal' in store)) store.chatModeGlobal = '';
if (!('impactDraftGlobal' in store)) store.impactDraftGlobal = null;
if (!('impactPrecheckGlobal' in store)) store.impactPrecheckGlobal = { done: false, checked_at: null, status: '' };
if (!('awaitingImpactNeedGlobal' in store)) store.awaitingImpactNeedGlobal = false;
if (!('pendingImpactProceedGlobal' in store)) store.pendingImpactProceedGlobal = { awaiting: false };
if (!('lastSuggestedImpactPayloadGlobal' in store)) store.lastSuggestedImpactPayloadGlobal = null;

const pushMemory = (role, content) => {
  const text = toStr(content);
  if (!text) return;
  store.chatMemory[sessionId].push({ role, content: text, at: new Date().toISOString() });
  if (store.chatMemory[sessionId].length > 40) {
    store.chatMemory[sessionId] = store.chatMemory[sessionId].slice(-40);
  }
};

const chatHistory = () => store.chatMemory[sessionId].slice(-12).map((t) => ({ role: t.role, content: t.content }));

const getMode = () => toStr(store.chatModes[sessionId] || store.chatModeGlobal || '');
const setMode = (mode) => {
  const m = toStr(mode);
  store.chatModes[sessionId] = m;
  store.chatModeGlobal = m;
};
const clearMode = () => {
  delete store.chatModes[sessionId];
  store.chatModeGlobal = '';
};

const getPrecheck = () => {
  const s = store.impactPrecheck[sessionId] || store.impactPrecheckGlobal;
  if (!s || typeof s !== 'object') return { done: false, checked_at: null, status: '' };
  return { done: !!s.done, checked_at: s.checked_at || null, status: toStr(s.status || '') };
};
const setPrecheck = (state) => {
  const payload = { done: !!state?.done, checked_at: state?.checked_at || null, status: toStr(state?.status || '') };
  store.impactPrecheck[sessionId] = payload;
  store.impactPrecheckGlobal = payload;
};
const clearPrecheck = () => {
  delete store.impactPrecheck[sessionId];
  store.impactPrecheckGlobal = { done: false, checked_at: null, status: '' };
};

const getDraft = () => {
  const d = store.impactDrafts[sessionId] || store.impactDraftGlobal;
  if (!d || typeof d !== 'object') return null;
  return d;
};
const setDraft = (draft) => {
  store.impactDrafts[sessionId] = draft;
  store.impactDraftGlobal = draft;
};
const clearDraft = () => {
  delete store.impactDrafts[sessionId];
  store.impactDraftGlobal = null;
};

const setAwaitingImpactNeed = (flag) => {
  const f = !!flag;
  store.awaitingImpactNeed[sessionId] = f;
  store.awaitingImpactNeedGlobal = f;
};
const clearAwaitingImpactNeed = () => {
  delete store.awaitingImpactNeed[sessionId];
  store.awaitingImpactNeedGlobal = false;
};

const getPendingProceed = () => {
  const p = store.pendingImpactProceed[sessionId] || store.pendingImpactProceedGlobal;
  if (!p || typeof p !== 'object') return { awaiting: false };
  return {
    awaiting: !!p.awaiting,
    status: toStr(p.status || ''),
    analysis_text: toStr(p.analysis_text || ''),
    suggested_payload: p.suggested_payload || null,
    created_at: p.created_at || null
  };
};
const setPendingProceed = (payload) => {
  const normalized = {
    awaiting: !!payload?.awaiting,
    status: toStr(payload?.status || ''),
    analysis_text: toStr(payload?.analysis_text || ''),
    suggested_payload: payload?.suggested_payload || null,
    created_at: payload?.created_at || new Date().toISOString()
  };
  store.pendingImpactProceed[sessionId] = normalized;
  store.pendingImpactProceedGlobal = normalized;
};
const clearPendingProceed = () => {
  delete store.pendingImpactProceed[sessionId];
  store.pendingImpactProceedGlobal = { awaiting: false };
};

const getLastSuggestedPayload = () => store.lastSuggestedImpactPayload[sessionId] || store.lastSuggestedImpactPayloadGlobal || null;
const clearLastSuggestedPayload = () => {
  delete store.lastSuggestedImpactPayload[sessionId];
  store.lastSuggestedImpactPayloadGlobal = null;
};

const menuText = [
  'Escolha uma opcao para continuar (envie apenas 1, 2 ou 3):',
  '1) Nova analise de Impacto',
  '2) Duvida sobre funcionalidade ja implementada',
  '3) Correcao de PRs abertas',
  '',
  'Comandos uteis:',
  '- /menu: voltar para este menu',
  '- /reset: limpar modo e reiniciar conversa'
].join('\n');

pushMemory('user', message);

const choiceMatch = lower.match(/^([123])\s*[\).:-]?\s*$/);
const selectedChoice = choiceMatch ? choiceMatch[1] : '';
const modeFromChoice = selectedChoice === '1'
  ? 'impact'
  : selectedChoice === '2'
  ? 'pr_qa'
  : selectedChoice === '3'
  ? 'correction_propose'
  : '';

if (lower === '/reset') {
  clearMode();
  clearDraft();
  clearPrecheck();
  clearAwaitingImpactNeed();
  clearPendingProceed();
  clearLastSuggestedPayload();
  return [{ json: { route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: 'Conversa reiniciada.\n\n' + menuText } }];
}

if (lower === '/menu') {
  clearMode();
  clearDraft();
  clearPrecheck();
  clearAwaitingImpactNeed();
  clearPendingProceed();
  clearLastSuggestedPayload();
  return [{ json: { route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: menuText } }];
}

if (modeFromChoice) {
  const previousMode = getMode();
  setMode(modeFromChoice);

  if (previousMode === 'impact' && modeFromChoice !== 'impact') {
    clearDraft();
  }

  if (modeFromChoice === 'impact') {
    clearDraft();
    clearPendingProceed();
    clearLastSuggestedPayload();
    setPrecheck({ done: false, checked_at: null, status: '' });
    setAwaitingImpactNeed(true);
    return [{
      json: {
        route: 'impact_collect_question',
        session_id: sessionId,
        chat_history: chatHistory(),
        output: [
          'Opcao 1 selecionada: Nova analise de Impacto.',
          'Antes da analise, vou verificar automaticamente se isso ja foi implementado (escopo: PRs merged).',
          '',
          'Agora descreva a necessidade em linguagem natural.'
        ].join('\n')
      }
    }];
  }

  clearPrecheck();
  clearAwaitingImpactNeed();
  clearPendingProceed();
  clearLastSuggestedPayload();

  if (modeFromChoice === 'pr_qa') {
    return [{ json: { route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: 'Opcao 2 selecionada: Duvida sobre funcionalidade ja implementada.\nAgora envie sua pergunta em linguagem natural.' } }];
  }

  if (modeFromChoice === 'correction_propose') {
    return [{ json: { route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: 'Opcao 3 selecionada: Correcao de PRs abertas.\nAgora descreva a correcao desejada em linguagem natural.' } }];
  }
}

const yes = ['sim', 's', 'yes', 'y', 'ok', 'pode', 'prosseguir', 'pode prosseguir', 'pode seguir'];
const no = ['nao', 'não', 'n', 'no', 'cancelar', 'parar', 'nao prosseguir', 'não prosseguir'];
const isYes = yes.includes(lower) || /^(sim|yes)\b/.test(lower);
const isNo = no.includes(lower) || /^(nao|não|no)\b/.test(lower);

const pendingProceed = getPendingProceed();
const precheckState = getPrecheck();
const precheckNeedsConfirm = precheckState.done && ['PARCIAL', 'NAO', 'SEM_EVIDENCIA'].includes(toStr(precheckState.status));

if (pendingProceed.awaiting || precheckNeedsConfirm) {
  const fallbackPayload = pendingProceed.suggested_payload || getLastSuggestedPayload() || {
    problema: 'Necessidade avaliada no pre-check de PRs',
    mudanca: 'Implementar a necessidade conforme diagnostico tecnico da analise de PRs.',
    evidencias: pendingProceed.analysis_text || '',
    restricoes: 'Sem restricoes adicionais informadas.'
  };

  if (isYes) {
    clearPendingProceed();
    clearAwaitingImpactNeed();
    setMode('impact');

    return [{
      json: {
        route: 'impact_run_manual',
        session_id: sessionId,
        chat_history: chatHistory(),
        impact_payload: fallbackPayload,
        output: [
          'Confirmado. Vou prosseguir com a implementacao e acionar o fluxo Impact Analysis.',
          '',
          'Impact Inputs utilizados:',
          '- problema: ' + toStr(fallbackPayload.problema || ''),
          '- mudanca: ' + toStr(fallbackPayload.mudanca || ''),
          '- evidencias: ' + toStr(fallbackPayload.evidencias || ''),
          '- restricoes: ' + toStr(fallbackPayload.restricoes || '')
        ].join('\n')
      }
    }];
  }

  if (isNo) {
    clearPendingProceed();
    clearAwaitingImpactNeed();
    clearMode();
    return [{
      json: {
        route: 'impact_collect_question',
        session_id: sessionId,
        chat_history: chatHistory(),
        output: [
          'Entendido. Nao vou prosseguir com a implementacao neste momento.',
          '',
          menuText
        ].join('\n')
      }
    }];
  }

  return [{
    json: {
      route: 'impact_collect_question',
      session_id: sessionId,
      chat_history: chatHistory(),
      output: 'Deseja prosseguir com a implementacao? Responda apenas: SIM ou NAO.'
    }
  }];
}

const lastSuggestedPayload = getLastSuggestedPayload();
if ((isYes || isNo) && !pendingProceed.awaiting && !precheckNeedsConfirm && lastSuggestedPayload) {
  if (isYes) {
    clearPendingProceed();
    clearAwaitingImpactNeed();
    setMode('impact');
    return [{
      json: {
        route: 'impact_run_manual',
        session_id: sessionId,
        chat_history: chatHistory(),
        impact_payload: lastSuggestedPayload,
        output: [
          'Confirmado. Vou prosseguir com a implementacao e acionar o fluxo Impact Analysis.',
          '',
          'Impact Inputs utilizados:',
          '- problema: ' + toStr(lastSuggestedPayload.problema || ''),
          '- mudanca: ' + toStr(lastSuggestedPayload.mudanca || ''),
          '- evidencias: ' + toStr(lastSuggestedPayload.evidencias || ''),
          '- restricoes: ' + toStr(lastSuggestedPayload.restricoes || '')
        ].join('
')
      }
    }];
  }

  clearPendingProceed();
  clearAwaitingImpactNeed();
  clearMode();
  return [{
    json: {
      route: 'impact_collect_question',
      session_id: sessionId,
      chat_history: chatHistory(),
      output: [
        'Entendido. Nao vou prosseguir com a implementacao neste momento.',
        '',
        menuText
      ].join('
')
    }
  }];
}

const currentMode = getMode();
if (!currentMode) {
  if (isYes || isNo) {
    return [{
      json: {
        route: 'impact_collect_question',
        session_id: sessionId,
        chat_history: chatHistory(),
        output: [
          'Nao ha confirmacao pendente neste momento.',
          '',
          menuText
        ].join('
')
      }
    }];
  }

  if (!selectedChoice && !lower.startsWith('/')) {
    const greetings = new Set(['oi','ola','olá','hello','hi','bom dia','boa tarde','boa noite','menu','ajuda','help','start','iniciar']);
    if (greetings.has(lower)) {
      return [{ json: { route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: menuText } }];
    }

    setMode('impact');
    setPrecheck({ done: false, checked_at: null, status: '' });
    setAwaitingImpactNeed(false);
    return [{
      json: {
        route: 'pr_qa_precheck',
        session_id: sessionId,
        chat_history: chatHistory(),
        question: 'essa necessidade ja foi implementada? ' + message,
        precheck_original_message: message,
        owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
        github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
        llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
      }
    }];
  }

  return [{ json: { route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: menuText } }];
}

if (currentMode === 'pr_qa') {
  const cachedQa = store.qaCache[lower];
  if (cachedQa && toStr(cachedQa.output)) {
    return [{
      json: {
        route: 'impact_collect_question',
        session_id: sessionId,
        chat_history: chatHistory(),
        output: [
          'Resposta reaproveitada da memoria para a mesma pergunta:',
          '',
          toStr(cachedQa.output)
        ].join('\n')
      }
    }];
  }

  return [{
    json: {
      route: 'pr_qa',
      session_id: sessionId,
      chat_history: chatHistory(),
      question: message,
      owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
      github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
      llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
    }
  }];
}

if (currentMode === 'correction_propose') {
  return [{
    json: {
      route: 'correction_propose',
      session_id: sessionId,
      chat_history: chatHistory(),
      question: message,
      owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
      github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
      llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
    }
  }];
}

const cancelImpact = lower === '/cancelar' || lower === 'cancelar' || lower === '/cancel';
if (cancelImpact) {
  clearDraft();
  clearPendingProceed();
  clearLastSuggestedPayload();
  setPrecheck({ done: false, checked_at: null, status: '' });
  setAwaitingImpactNeed(true);
  return [{ json: { route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output: 'Coleta de Impact Analysis cancelada.\nDescreva novamente a necessidade para eu executar a verificacao previa.' } }];
}

if (!precheckState.done) {
  const cachedPrecheck = store.precheckCache[lower];
  if (cachedPrecheck && ['SIM', 'PARCIAL', 'NAO', 'SEM_EVIDENCIA'].includes(toStr(cachedPrecheck.status))) {
    setPrecheck({ done: true, status: toStr(cachedPrecheck.status), checked_at: toStr(cachedPrecheck.updated_at || new Date().toISOString()) });

    if (toStr(cachedPrecheck.status) === 'SIM') {
      clearMode();
      return [{
        json: {
          route: 'impact_collect_question',
          session_id: sessionId,
          chat_history: chatHistory(),
          output: [
            'Reaproveitei a analise anterior para a mesma necessidade (status SIM).',
            'Nao vou prosseguir com Impact Analysis.',
            '',
            toStr(cachedPrecheck.analysis_text || ''),
            '',
            'Se quiser iniciar uma nova solicitacao, envie /menu.'
          ].join('\n')
        }
      }];
    }

    const suggested = cachedPrecheck.suggested_payload || {
      problema: message,
      mudanca: 'Prosseguir com implementacao/correcao com base na analise anterior de PRs.',
      evidencias: toStr(cachedPrecheck.analysis_text || ''),
      restricoes: 'Manter compatibilidade com PRs existentes e evitar regressao funcional.'
    };

    setPendingProceed({ awaiting: true, status: toStr(cachedPrecheck.status), analysis_text: toStr(cachedPrecheck.analysis_text || ''), suggested_payload: suggested });
    setAwaitingImpactNeed(false);

    return [{
      json: {
        route: 'impact_collect_question',
        session_id: sessionId,
        chat_history: chatHistory(),
        output: [
          'Reaproveitei a analise anterior para a mesma necessidade (status ' + toStr(cachedPrecheck.status) + ').',
          '',
          toStr(cachedPrecheck.analysis_text || ''),
          '',
          'Deseja prosseguir com a implementacao?',
          'Responda apenas: SIM ou NAO.'
        ].join('\n')
      }
    }];
  }

  setAwaitingImpactNeed(false);
  return [{
    json: {
      route: 'pr_qa_precheck',
      session_id: sessionId,
      chat_history: chatHistory(),
      question: 'essa necessidade ja foi implementada? ' + message,
      precheck_original_message: message,
      owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
      github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
      llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
    }
  }];
}

const parseLabeled = (text, labels) => {
  for (const label of labels) {
    const re = new RegExp(label + '\\s*[:=]\\s*([^|\\n]+)', 'i');
    const m = text.match(re);
    if (m) return toStr(m[1]);
  }
  return '';
};

const ensureDraft = () => {
  const existing = getDraft();
  if (existing) return existing;
  const created = {
    problema: '',
    mudanca: '',
    evidencias: '',
    restricoes: '',
    started_at: new Date().toISOString()
  };
  setDraft(created);
  return created;
};

const nextQuestion = (draft) => {
  if (!toStr(draft.problema)) return '1/4 Qual problema ou oportunidade essa alteracao resolve?';
  if (!toStr(draft.mudanca)) return '2/4 Descreva a mudanca como voce espera ver no produto.';
  if (!toStr(draft.evidencias)) return '3/4 Quais evidencias comprovam que a entrega esta pronta?';
  if (!toStr(draft.restricoes)) return '4/4 Restricoes: limites de prazo, compliance, integracoes proibidas, etc.';
  return '';
};

const summaryDraft = (draft) => [
  '- problema: ' + (toStr(draft.problema) || '(pendente)'),
  '- mudanca: ' + (toStr(draft.mudanca) || '(pendente)'),
  '- evidencias: ' + (toStr(draft.evidencias) || '(pendente)'),
  '- restricoes: ' + (toStr(draft.restricoes) || '(pendente)')
].join('\n');

const draft = ensureDraft();

const p = parseLabeled(message, ['problema', 'problem']);
const m = parseLabeled(message, ['mudanca', 'mudança', 'expected_change']);
const e = parseLabeled(message, ['evidencias', 'evidências', 'evidence']);
const r = parseLabeled(message, ['restricoes', 'restrições', 'constraints']);

if (p) draft.problema = p;
if (m) draft.mudanca = m;
if (e) draft.evidencias = e;
if (r) draft.restricoes = r;

const notLabeled = !(p || m || e || r || modeFromChoice);
if (notLabeled) {
  if (!toStr(draft.problema)) draft.problema = message;
  else if (!toStr(draft.mudanca)) draft.mudanca = message;
  else if (!toStr(draft.evidencias)) draft.evidencias = message;
  else if (!toStr(draft.restricoes)) draft.restricoes = message;
}

setDraft(draft);

const next = nextQuestion(draft);
if (next) {
  return [{
    json: {
      route: 'impact_collect_question',
      session_id: sessionId,
      chat_history: chatHistory(),
      output: [
        'Opcao 1 ativa: Nova analise de Impacto (pre-check concluido).',
        '',
        summaryDraft(draft),
        '',
        next,
        '',
        'Dica: voce pode responder por partes ou enviar tudo rotulado: problema:, mudanca:, evidencias:, restricoes:.'
      ].join('\n')
    }
  }];
}

const payload = {
  problema: toStr(draft.problema),
  mudanca: toStr(draft.mudanca),
  evidencias: toStr(draft.evidencias),
  restricoes: toStr(draft.restricoes)
};

clearDraft();
clearAwaitingImpactNeed();
clearPendingProceed();
clearLastSuggestedPayload();

return [{
  json: {
    route: 'impact_run_manual',
    session_id: sessionId,
    chat_history: chatHistory(),
    impact_payload: payload,
    output: [
      'Dados coletados. Vou disparar o subflow de Impact Analysis agora.',
      '',
      summaryDraft(payload)
    ].join('\n')
  }
}];
